DECLARE @logFileType SMALLINT= 1;
DECLARE @start DATETIME;
DECLARE @end DATETIME;
DECLARE @logno INT= 0;
SET @start = DATEADD(MINUTE, -5, GETDATE());
SET @end = GETDATE();
DECLARE @searchString1 NVARCHAR(256)= 'Severity:';
DECLARE @searchString2 NVARCHAR(256)= 'MSDB';
SET @searchString2 = NULL;
DECLARE @logtable TABLE(LogDate DATETIME2, ProcessInfo NVARCHAR(250), [Text] NVARCHAR(500))
INSERT INTO @logtable
EXEC master.dbo.xp_readerrorlog
     @logno,
     @logFileType,
     @searchString1,
     @searchString2,
     @start,
     @end;
SELECT COUNT(*) [value] 
FROM @logtable
WHERE [Text] LIKE '%Severity: 1[7-9]%'
OR [Text] LIKE '%Severity: 2%'

